// 将表格中"同上"替换为上方单元格值，"同左"替换为左侧单元格值
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var replacedCount = 0;

for (var t = 0; t < tables.Count; t++) {
    var table = tables.Item(t);
    var rows = table.Rows.Count;
    var cols = table.Columns.Count;

    for (var r = 0; r < rows; r++) {
        for (var c = 0; c < cols; c++) {
            var cell = table.Cell(r + 1, c + 1);
            var text = cell.Range.Text.trim();

            if (text === "同上") {
                if (r > 0) {
                    var aboveCell = table.Cell(r, c + 1);
                    var aboveText = aboveCell.Range.Text.trim();
                    cell.Range.Text = aboveText;
                    replacedCount++;
                }
            } else if (text === "同左") {
                if (c > 0) {
                    var leftCell = table.Cell(r + 1, c);
                    var leftText = leftCell.Range.Text.trim();
                    cell.Range.Text = leftText;
                    replacedCount++;
                }
            }
        }
    }
}

return "共替换" + replacedCount + "个'同上'或'同左'";

